function Chip({ children, tone = "muted" }) {
  const tones = {
    muted: { bg: "#F1F3F6", fg: "#5B6470" },
    blue: { bg: "#EAF0FF", fg: "#3B6FF2" },
    green: { bg: "#E6F7EC", fg: "#16A34A" },
    yellow: { bg: "#FEF3C7", fg: "#B45309" },
    red: { bg: "#FEE2E2", fg: "#DC2626" },
  };
  const t = tones[tone];
  return (
    <span style={{ background: t.bg, color: t.fg, fontSize: 12, fontWeight: 700, letterSpacing: 0.3, padding: "3px 8px", borderRadius: 999 }}>
      {children}
    </span>
  );
}

function Card({ children, style }) {
  return (
    <div style={{ background: "#fff", borderRadius: 18, boxShadow: "0 1px 2px rgba(20,24,32,0.04), 0 8px 24px -12px rgba(20,24,32,0.10)", border: "1px solid #ECEEF1", padding: 18, ...style }}>
      {children}
    </div>
  );
}

function PrimaryButton({ children, onClick, disabled, full = true }) {
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      style={{
        width: full ? "100%" : "auto",
        background: disabled ? "#C7D0E0" : "#3B6FF2",
        color: "#fff",
        fontWeight: 700,
        fontSize: 16,
        border: "none",
        borderRadius: 14,
        padding: "16px 20px",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        gap: 8,
        cursor: disabled ? "not-allowed" : "pointer",
        boxShadow: disabled ? "none" : "0 6px 16px -6px rgba(59,111,242,0.55)",
        transition: "transform 0.08s ease",
      }}
      onMouseDown={(e) => !disabled && (e.currentTarget.style.transform = "scale(0.98)")}
      onMouseUp={(e) => (e.currentTarget.style.transform = "scale(1)")}
    >
      {children}
    </button>
  );
}

function ProgressBar({ label, value, total, color }) {
  const pct = total > 0 ? Math.min(100, Math.round((value / total) * 100)) : 0;
  return (
    <div>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "baseline", marginBottom: 5 }}>
        <span style={{ fontSize: 12, fontWeight: 700, color: "#5B6470" }}>{label}</span>
        <span style={{ fontSize: 11.5, fontWeight: 700, color: color }}>{value}/{total}</span>
      </div>
      <div style={{ height: 6, borderRadius: 999, background: "#E4E8EE", overflow: "hidden" }}>
        <div style={{ width: `${pct}%`, height: "100%", background: color, borderRadius: 999, transition: "width 0.3s ease" }} />
      </div>
    </div>
  );
}

function ProgressRing({ label, value, total, color, size = 28 }) {
  const stroke = 3;
  const r = (size - stroke) / 2;
  const c = 2 * Math.PI * r;
  const pct = total > 0 ? Math.min(1, value / total) : 0;
  const offset = c * (1 - pct);
  return (
    <div style={{ width: 40, display: "flex", flexDirection: "column", alignItems: "center", gap: 2 }}>
      <span style={{ fontSize: 9, fontWeight: 700, color: "#8A93A3", letterSpacing: 0.2, whiteSpace: "nowrap", lineHeight: 1 }}>{label}</span>
      <div style={{ position: "relative", width: size, height: size }}>
        <svg width={size} height={size} style={{ transform: "rotate(-90deg)" }}>
          <circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke="#E4E8EE" strokeWidth={stroke} />
          <circle cx={size / 2} cy={size / 2} r={r} fill="none" stroke={color} strokeWidth={stroke} strokeLinecap="round" strokeDasharray={c} strokeDashoffset={offset} style={{ transition: "stroke-dashoffset 0.3s ease" }} />
        </svg>
        <div style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 9, fontWeight: 800, color: "#1B2430" }}>{value}/{total}</div>
      </div>
    </div>
  );
}

