function Barcode({ value }) {
  const digits = value.replace(/\s+/g, "");
  const bars = [];
  for (let i = 0; i < 46; i++) {
    const code = digits.charCodeAt(i % digits.length) || 55;
    bars.push({ w: (code % 3) + 1, black: i % 2 === 0 });
  }
  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center" }}>
      <div style={{ display: "flex", alignItems: "stretch", justifyContent: "center", height: 30 }}>
        {bars.map((b, i) => (
          <div key={i} style={{ width: b.w, background: b.black ? "#1B2430" : "transparent" }} />
        ))}
      </div>
      <div style={{ fontSize: 12, letterSpacing: 2, color: "#1B2430", fontWeight: 600, marginTop: 5, fontFamily: "ui-monospace, monospace", textAlign: "center" }}>{value}</div>
    </div>
  );
}

