function ShelfSlideshow({ frames, durations, aspect }) {
  const [i, setI] = useState(0);
  useEffect(() => {
    const d = (durations && durations[i]) || 1000;
    const t = setTimeout(() => setI((p) => (p + 1) % frames.length), d);
    return () => clearTimeout(t);
  }, [i, frames.length, durations]);
  return (
    <div style={{ width: "100%", aspectRatio: aspect, borderRadius: 10, overflow: "hidden", background: "transparent" }}>
      <img src={frames[i]} alt="Shelf move sequence" style={{ width: "100%", height: "100%", objectFit: "contain", display: "block" }} />
    </div>
  );
}

