function ClickRipple() {
  const [ripples, setRipples] = useState([]);
  useEffect(() => {
    let id = 0;
    const MOVE_TOL = 10; // px; a drag/scroll past this cancels the ripple
    let start = null;
    const onDown = (e) => { start = { x: e.clientX, y: e.clientY, t: Date.now() }; };
    const onMove = (e) => {
      if (!start) return;
      if (Math.abs(e.clientX - start.x) > MOVE_TOL || Math.abs(e.clientY - start.y) > MOVE_TOL) start = null;
    };
    const onUp = (e) => {
      if (!start) return;
      const moved = Math.abs(e.clientX - start.x) > MOVE_TOL || Math.abs(e.clientY - start.y) > MOVE_TOL;
      start = null;
      if (moved) return;
      const r = { id: id++, x: e.clientX, y: e.clientY };
      setRipples((list) => [...list, r]);
      setTimeout(() => setRipples((list) => list.filter((p) => p.id !== r.id)), 650);
    };
    const onCancel = () => { start = null; };
    window.addEventListener("pointerdown", onDown, true);
    window.addEventListener("pointermove", onMove, true);
    window.addEventListener("pointerup", onUp, true);
    window.addEventListener("pointercancel", onCancel, true);
    return () => {
      window.removeEventListener("pointerdown", onDown, true);
      window.removeEventListener("pointermove", onMove, true);
      window.removeEventListener("pointerup", onUp, true);
      window.removeEventListener("pointercancel", onCancel, true);
    };
  }, []);

  return (
    <div style={{ position: "fixed", inset: 0, pointerEvents: "none", zIndex: 9999 }}>
      {ripples.map((r) => (
        <span
          key={r.id}
          style={{
            position: "fixed",
            left: r.x,
            top: r.y,
            width: 26,
            height: 26,
            marginLeft: -13,
            marginTop: -13,
            borderRadius: "50%",
            border: "3px solid #3B6FF2",
            background: "rgba(59,111,242,0.28)",
            animation: "clickRipple 0.65s ease-out forwards",
          }}
        />
      ))}
    </div>
  );
}

export default function App() {
  const [screen, setScreen] = useState("login"); // login | assignments | section | scan | items
  const [section, setSection] = useState(null);
  const [shelf, setShelf] = useState(START_SHELF);
  const [toast, setToast] = useState(false);
  const [blink, setBlink] = useState(false);
  const [overrideShelf, setOverrideShelf] = useState(null);
  const [doneSections, setDoneSections] = useState([]);
  const [itemIdx, setItemIdx] = useState(0);

  // A single token that identifies the current view. It changes on any navigation —
  // including shelf-to-shelf steps that keep `screen` the same. Used to (a) scroll to
  // the top and (b) remount the screen so any open help guides reset to closed.
  const viewKey = [screen, section?.id ?? "-", shelf, overrideShelf ?? "-"].join("|");

  useEffect(() => {
    window.scrollTo(0, 0);
    if (document.scrollingElement) document.scrollingElement.scrollTop = 0;
    if (document.documentElement) document.documentElement.scrollTop = 0;
    if (document.body) document.body.scrollTop = 0;
  }, [viewKey]);

  const fireToast = () => {
    setToast(true);
    setBlink(false);
    const timers = [
      setTimeout(() => setBlink(true), 500),
      setTimeout(() => setBlink(false), 1000),
      setTimeout(() => setBlink(true), 1500),
      setTimeout(() => { setToast(false); setBlink(false); }, 2000),
    ];
    return () => timers.forEach(clearTimeout);
  };

  return (
    <div style={{ background: "#F4F5F7", minHeight: "100vh", display: "flex", justifyContent: "center", fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', Inter, sans-serif" }}>
      <div style={{ width: "100%", maxWidth: 420, padding: "22px 16px 40px" }}>
        <style>{`@keyframes ledFlash { 0%, 100% { opacity: 1; } 50% { opacity: 0.12; } } @keyframes railBlink { 0%, 49.99% { opacity: 1; } 50%, 100% { opacity: 0; } } @keyframes clickRipple { 0% { transform: scale(0.35); opacity: 1; } 100% { transform: scale(2.6); opacity: 0; } }`}</style>
        <ClickRipple />
        {toast && (
          <div style={{ position: "fixed", bottom: "calc(18px + env(safe-area-inset-bottom, 0px))", left: 0, right: 0, display: "flex", justifyContent: "center", padding: "0 20px", zIndex: 60, pointerEvents: "none" }}>
            <div style={{ background: "#E2E4E7", borderRadius: 20, padding: "14px 16px", width: "100%", maxWidth: 320, boxShadow: "0 14px 34px -12px rgba(11,31,58,0.35)" }}>
              <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 8, marginBottom: 10 }}>
                <Check size={17} color="#1E9E5A" />
                <span style={{ fontSize: 14, fontWeight: 800, color: "#1B2430" }}>Matching sent successfully</span>
              </div>
              <div style={{ width: "70%", margin: "0 auto", aspectRatio: "825 / 201" }}>
                <img src={blink ? RAIL_GREEN_IMG : RAIL_EMPTY_IMG} alt="" style={{ width: "100%", height: "100%", objectFit: "contain", display: "block" }} />
              </div>
            </div>
          </div>
        )}
        <div key={viewKey}>
        {screen === "login" && <LoginScreen onLogin={() => setScreen("assignments")} />}

        {screen === "assignments" && (
          <AssignmentsScreen
            done={doneSections}
            onBack={() => setScreen("login")}
            onSelectSection={(s) => {
              setSection(s);
              setShelf(START_SHELF);
              setScreen("overview");
            }}
          />
        )}

        {screen === "overview" && section && (
          <OverviewScreen
            sectionName={section.name}
            sectionMoves={section.moves}
            onBack={() => setScreen("assignments")}
            onHome={() => setScreen("assignments")}
            onStart={() => setScreen("section")}
          />
        )}

        {screen === "section" && section && (
          <ShelfScreen
            sectionName={section.name}
            shelf={shelf}
            sectionMoves={section.moves}
            isLast={shelf === LAST_SHELF}
            onBack={() => {
              if (shelf >= START_SHELF) {
                setScreen("overview");
              } else {
                setShelf((s) => s + 1);
              }
            }}
            onHome={() => setScreen("assignments")}
            onBackToStart={() => setShelf(START_SHELF)}
            onOverride={(sh) => { setOverrideShelf(sh); setScreen("scan"); }}
            onNextShelf={() => {
              fireToast();
              if (shelf === LAST_SHELF) {
                setScreen("assignments");
              } else {
                setShelf((s) => s - 1);
              }
            }}
          />
        )}

        {screen === "scan" && (
          <ScanScreen
            shelf={overrideShelf}
            sectionName={section?.name}
            sectionMoves={section?.moves}
            onBack={() => setScreen("section")}
            onHome={() => setScreen("assignments")}
            onFinish={() => {
              fireToast();
              if (overrideShelf === LAST_SHELF) {
                setScreen("tagsetup");
              } else {
                setShelf(overrideShelf - 1);
                setScreen("section");
              }
            }}
          />
        )}

        {screen === "recap" && (
          <RecapScreen
            sectionName={section?.name}
            sectionMoves={section?.moves}
            onBack={() => setScreen("items")}
            onHome={() => setScreen("assignments")}
            onItemMoves={() => {
              if (section) setDoneSections((d) => (d.includes(section.id) ? d : [...d, section.id]));
              setScreen("assignments");
            }}
          />
        )}

        {screen === "tagsetup" && (
          <TagSetupScreen
            sectionName={section?.name}
            sectionMoves={section?.moves}
            onBack={() => { setShelf(LAST_SHELF); setScreen("section"); }}
            onHome={() => setScreen("assignments")}
            onItemMoves={() => { setItemIdx(0); setScreen("items"); }}
          />
        )}

        {screen === "items" && section && (
          <ItemMovesScreen
            sectionName={section?.name}
            idx={itemIdx}
            setIdx={setItemIdx}
            onBack={() => setScreen("tagsetup")}
            onHome={() => setScreen("assignments")}
            onFinish={() => setScreen("recap")}
          />
        )}
        </div>
      </div>
    </div>
  );
}
